INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('os seguintes diplomas:   - Lei n.º 5-A/2002, de 11 de Janeiro   - Lei n.º 75/2013, de 12 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 169/99, de 18 de Setembro    - 2ª versão: Lei n.º 5-A/2002, de 11 de Janeiro   
     
                         
                          
