INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('Nº de artigos:20  
    
  Lei n.º 103/2015, de 24 de Agosto  (versão actualizada) AUTODETERMINAÇÃO SEXUAL E LIBERDADE SEXUAL DE MENOR - IDENTIFICAÇÃO CRIMINAL DE CONDENADOS    
    
 
  
                         
                          
SUMÁRIOTrigésima nona alteração ao Código Penal, aprovado pelo Decreto-Lei n.º 400/82, de 23 de setembro, transpondo a Diretiva 2011/93/UE, do Parlamento Europeu e do Conselho, de 13 de dezembro de 2011, e cria o sistema de registo de identificação criminal de condenados pela prática de crimes contra a autodeterminação sexual e a liberdade sexual de menor; primeira alteração à Lei n.º 113/2009, de 17 de setembro; primeira alteração à Lei n.º 67/98, de 26 de outubro, e segunda alteração à Lei n.º 37/2008, de 6 de agosto
Lei n.º 103/2015, de 24 de agosto
  Trigésima nona alteração ao Código Penal, aprovado pelo Decreto-Lei n.º 400/82, de 23 de setembro, transpondo a Diretiva 2011/93/UE, do Parlamento Europeu e do Conselho, de 13 de dezembro de 2011, e cria o sistema de registo de identificação criminal de condenados pela prática de crimes contra a autodeterminação sexual e a liberdade sexual de menor; primeira alteração à Lei n.º 113/2009, de 17 de setembro; primeira alteração à Lei n.º 67/98, de 26 de outubro, e segunda alteração à Lei n.º 37/2008, de 6 de agosto.
  A Assembleia da República decreta, nos termos da alínea c) do artigo 161.º da Constituição, o seguinte:
  
  Artigo 1.º
  Objeto
  A presente lei procede à trigésima nona alteração ao Código Penal, aprovado pelo Decreto-Lei n.º 400/82, de 23 de setembro, transpondo a Diretiva 2011/93/UE, do Parlamento Europeu e do Conselho, de 13 de dezembro de 2011, cria o sistema de registo de identificação criminal de condenados pela prática de crimes contra a autodeterminação sexual e a liberdade sexual de menor, e procede à primeira alteração à Lei n.º 113/2009, de 17 de setembro, que estabelece medidas de proteção de menores, à primeira alteração à Lei n.º 67/98, de 26 de outubro, e à segunda alteração à Lei n.º 37/2008, de 6 de agosto.
  
  Artigo 2.º
  Alteração ao Código Penal
  Os artigos 53.º, 54.º e 171.º a 177.º do  Código Penal, aprovado pelo Decreto-Lei n.º 400/82, de 23 de setembro, e alterado pela Lei n.º 6/84, de 11 de maio, pelos Decretos-Leis n.os 101-A/88, de 26 de março, 132/93, de 23 de abril, e 48/95, de 15 de março, pelas Leis n.os 90/97, de 30 de julho, 65/98, de 2 de setembro, 7/2000, de 27 de maio, 77/2001, de 13 de julho, 97/2001, 98/2001, 99/2001 e 100/2001, de 25 de agosto, e 108/2001, de 28 de novembro, pelos Decretos-Leis n.os 323/2001, de 17 de dezembro, e 38/2003, de 8 de março, pelas Leis n.os 52/2003, de 22 de agosto, e 100/2003, de 15 de novembro, pelo Decreto-Lei n.º 53/2004, de 18 de março, e pelas Leis n.os 11/2004 de 27 de março, 31/2004, de 22 de julho, 5/2006, de 23 de fevereiro, 16/2007, de 17 de abril, 59/2007, de 4 de setembro, 61/2008, de 31 de outubro, 32/2010, de 2 de setembro, 40/2010, de 3 de setembro, 4/2011, de 16','447');
